// コンストラクタはオーバーライドできませんが、親クラスのコンストラクタを呼び出すことは可能です。

public class Animal {
    public Animal() {
        System.out.println("An animal is created.");
    }
}

public class Dog extends Animal {
    public Dog() {
        super();
        System.out.println("A dog is created.");
    }
}

public class Main {
    public static void main(String[] args) {
        Dog myDog = new Dog();
        // 予想される出力:
        // An animal is created.
        // A dog is created.
    }
}

// 親クラスのpublicメソッドは、子クラスではpublicとしてオーバーライドする必要があります。

public class Animal {
    public void makeSound() {
        System.out.println("The animal makes a sound.");
    }
}

public class Dog extends Animal {
    @Override
    public void makeSound() {
        System.out.println("The dog barks.");
    }
}

public class Main {
    public static void main(String[] args) {
        Animal myDog = new Dog();
        myDog.makeSound();
        // 予想される出力:
        // The dog barks.
    }
}

// 親クラス
public class Parent {
    public void method() throws IOException {
        System.out.println("Parent method");
    }
}

// 子クラス
public class Child extends Parent {
    @Override
    public void method() throws IOException {
        System.out.println("Child method");
        throw new IOException();
    }
}

// Main
public class Main {
    public static void main(String[] args) {
        Parent obj = new Child();
        try {
            obj.method();
        } catch(IOException e) {
            System.out.println("Caught IOException");
            // 予想される出力:
            // Child method
            // Caught IOException
        }
    }
}

// 親クラス
public class Parent {
    private void method() {
        System.out.println("Parent's private method");
    }
}

// 子クラス
public class Child extends Parent {
    // これはオーバーライドではなく、新たなメソッドを定義したことになります。
    public void method() {
        System.out.println("Child's method");
    }
}

// Main
public class Main {
    public static void main(String[] args) {
        Child obj = new Child();
        obj.method();
        // 予想される出力:
        // Child's method
    }
}

// 抽象クラス
public abstract class AbstractAnimal {
    // 抽象メソッド
    public abstract void speak();
}

// 具象クラス
public class Dog extends AbstractAnimal {
    // 抽象メソッドをオーバーライド
    @Override
    public void speak() {
        System.out.println("Woof!"); // 予想される出力: Woof!
    }
}

// Main
public class Main {
    public static void main(String[] args) {
        Dog dog = new Dog();
        dog.speak();
    }
}

// スーパークラス
public class Animal {
    public void sound() {
        System.out.println("Animal sound"); // 予想される出力: Animal sound
    }
