// サブクラス1
public class Dog extends Animal {
    @Override
    public void sound() {
        System.out.println("Woof!"); // 予想される出力: Woof!
    }
}

// サブクラス2
public class Cat extends Animal {
    @Override
    public void sound() {
        System.out.println("Meow!"); // 予想される出力: Meow!
    }
}

// Main
public class Main {
    public static void main(String[] args) {
        Animal myDog = new Dog();
        Animal myCat = new Cat();
        myDog.sound();
        myCat.sound();
    }
}

