// 親クラス
public class Vehicle {
    public void move() {
        System.out.println("Vehicle is moving"); // 予想される出力: Vehicle is moving
    }
}

// Carクラス
public class Car extends Vehicle {
    @Override
    public void move() {
        super.move();
        System.out.println("Car is moving"); // 予想される出力: Car is moving
    }
}

// Main
public class Main {
    public static void main(String[] args) {
        Car myCar = new Car();
        myCar.move();
    }
}

// Animalクラス
public class Animal {
    public void makeSound() {
        System.out.println("Animal is making a sound"); // 予想される出力: Animal is making a sound
    }
}

// Dogクラス
public class Dog extends Animal {
    @Override
    public void makeSound() {
        System.out.println("Dog is barking"); // 予想される出力: Dog is barking
    }
}

// Catクラス
public class Cat extends Animal {
    @Override
    public void makeSound() {
        System.out.println("Cat is meowing"); // 予想される出力: Cat is meowing
    }
}

// Main
public class Main {
    public static void main(String[] args) {
        Animal[] animals = new Animal[] {new Dog(), new Cat()};
        for (Animal animal : animals) {
            animal.makeSound();
        }
    }
}
